//SOUND_BEGIN
//SOUND_BEGIN
// =========================================================================
// Title: Alien Thorns
// Author: Dave Hoskins
// Source: https://www.shadertoy.com/view/XsSSzD
// License: CC BY-NC-SA 3.0 (Creative Commons Attribution-NonCommercial-ShareAlike 3.0 Unported)
//
// Note: Adapted for Desktop GLSL Audio. Removed dependencies on iChannel0 
//       and iChannel3. Replaced with mathematical hash functions.
// =========================================================================
// =========================================================================
// Title: Voronoi Thorns Synth
// Note: Adattato per Desktop GLSL Audio. Rimosse le dipendenze da iChannel0 
// e iChannel3. Sostituite con funzioni di hash matematiche.
// =========================================================================

#define PI 3.14159265359
#define MOD3 vec3(0.0631, 0.07369, 0.08787)

float gTime;

//--------------------------------------------------------------------------------------------------
vec2 Hash2(vec2 p) {
    vec3 p3 = fract(vec3(p.xyx) * MOD3);
    p3 += dot(p3.zxy, p3.yxz + 19.19);
    return fract(vec2(p3.x * p3.y, p3.z * p3.x));
}

//--------------------------------------------------------------------------------------------------
vec2 Noise(in vec2 x) {
    return mix(Hash2(floor(x)), Hash2(floor(x) + 1.0), fract(x));
}

// Generatore di forma d'onda a dente di sega tramite sintesi additiva
float Saw(float n, float fil) {
    float v = 0.0;
    float f = 1.0;
    int filt = int(fil);

    for (int i = 0; i < 100; i++) {
        if (i > filt) break;
        float a = 0.5 * (sin(2.0 * f * n * PI) / f);
        if (i > filt - filt / 10) a = 2.5 * a;
        v += a;
        f++;
    }
    return v * 2000.0 / (fil + 1000.0);
}

// NUOVO HASH MATEMATICO (Sostituisce iChannel0)
vec2 Hash(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453123);
}

//--------------------------------------------------------------------------
vec2 Noise2D(in vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    vec2 res = mix(mix(Hash(p + 0.0), Hash(p + vec2(1.0, 0.0)), f.x),
                   mix(Hash(p + vec2(0.0, 1.0)), Hash(p + vec2(1.0, 1.0)), f.x), f.y);
    return res - 0.5;
}

//--------------------------------------------------------------------------
vec2 FBM(vec2 p) {
    vec2 f;
    f  = 0.50000 * Noise2D(p); p = p * 2.32;
    f += 0.25000 * Noise2D(p); p = p * 2.23;
    f += 0.12500 * Noise2D(p); p = p * 2.31;
    f += 0.06250 * Noise2D(p); p = p * 2.28;
    f += 0.03125 * Noise2D(p);
    return f;
}

//--------------------------------------------------------------------------------------------------
vec4 ThornVoronoi(vec3 p) {
    vec2 f = fract(p.xz);
    p.xz = floor(p.xz);
    float d = 1.0e10;
    vec3 id = vec3(0.0);

    for (int xo = -1; xo <= 1; xo++) {
        for (int yo = -1; yo <= 1; yo++) {
            vec2 g = vec2(xo, yo);

            // NUOVO HASH PER VORONOI (Sostituisce iChannel3)
            // Genera un vettore casuale stabile per la cella corrente
            vec2 n = Hash(p.xz + g);
            n = n * n * (3.0 - 2.0 * n);

            vec2 tp = g + 0.5 + sin(p.y + 1.2831 * (n * gTime * 0.5)) - f;
            float d2 = dot(tp, tp);
            if (d2 < d) {
                d = d2;
                id = vec3(tp.x, p.y, tp.y);
            }
        }
    }
    return vec4(id, 1.35 - pow(d, 0.17));
}

//--------------------------------------------------------------------------------------------------
float MapThorns(in vec3 pos) {
    return pos.y * 0.21 - ThornVoronoi(pos).w - max(pos.y - 5.0, 0.0) * 0.5 + max(pos.y - 5.5, 0.0) * 0.8;
}

//--------------------------------------------------------------------------------------------------
vec3 Path(float time) {
    return vec3(1.3 + 17.2 * cos(0.2 - 0.5 * 0.33 * time * 0.75), 
                4.7, 
                7.6 - 16.2 * sin(0.5 * 0.11 * time * 0.75));
}

//--------------------------------------------------------------------------------------------------
vec2 mainSound(int samp, float time) {
    gTime = time + 173.0;

    // Calcolo del percorso e della direzione
    vec3 ro = Path(gTime + 0.0);
    vec3 ta = Path(gTime + 5.2);
    float add = (sin(gTime * 0.3) + 1.0) * 2.0;
    ro.y += add;
    ta.y -= add;

    vec3 cw = normalize(ta - ro);     
    vec3 cp = vec3(0.0, 1.0, 0.0);    
    vec3 cu = normalize(cross(cw, cp)); 

    // Rilevamento della prossimità agli ostacoli (per l'orecchio destro e sinistro)
    vec2 ears;
    ears.x = abs(MapThorns(ro + cu * 0.1)) * 0.8;
    ears.y = abs(MapThorns(ro - cu * 0.1)) * 0.8;

    // Calcolo del guadagno volumetrico (se mi avvicino a un ostacolo, il suono cambia)
    vec2 gain = clamp(1.0 - ears, 0.0, 1.0);
    gain = pow(gain, vec2(3.9));

    // Frequenze di filtro dinamiche
    float fil1 = sin(gTime * 0.521) * 50.0 + 60.0;
    float fil2 = -sin(gTime * 0.474) * 50.0 + 60.0;

    // Generazione del suono base (Sintesi Additiva Sawtooth)
    vec2 audio;
    audio.x = gain.x * (Saw(11.125 * time, fil1) + Saw(22.2 * time, fil1));
    audio.y = gain.y * (Saw(11.125 * time, fil2) + Saw(22.3 * time, fil2));

    // Aggiunta di rumore turbolento basato sul movimento
    vec2 pos = vec2(gTime * 192.017331, gTime * 182.066927);
    pos -= sin(gTime * 0.143) * 20.0 * (gain.x + gain.y);
    audio += FBM(pos) * Saw(gTime * 10.5 - sin(gTime * 0.2) * 8.0, 30.0);

    // Fade out verso la fine della traccia
    return clamp(audio, -1.0, 1.0) * smoothstep(180.0, 175.0, time);
}
//SOUND_END

//SOUND_END

// --- PARAMETRI ---
// Imposta nel dock: Rosso (c1) e Bianco (c2) per l'effetto classico
vec3 c1 = u_col1;
vec3 c2 = u_col2;

// --- CONFIGURAZIONE SPIRALE ---
// Coils: Quante strisce vedi in una sezione trasversale del tubo
float coils = 6.0;

// Twists: Quanti giri completi fa la spirale lungo tutto il toro
// Deve essere un numero intero per evitare che la texture si tagli alla giunzione
float twists = 40.0;

// --- CALCOLO ---
// La magia è sommare U e V moltiplicati.
// (u * twists) spinge la texture lungo il percorso
// (v * coils) avvolge la texture attorno al tubo
// Sommando i due si ottiene una linea diagonale (elica/spirale)
float pos = (u * twists) + (v * coils);

// --- CREAZIONE STRISCE NETTE ---
// fract(pos) crea un dente di sega da 0.0 a 1.0 ripetuto
// step(0.5, ...) taglia di netto il valore: sotto 0.5 è 0, sopra è 1.
float stripe = step(0.5, fract(pos));

// Restituisce il colore (senza sfumature)
return mix(c1, c2, stripe);
